import { useState } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleFileChange = (e) => {
    setError(null);
    const selected = e.target.files[0];
    setFile(selected);
    setPreview(selected ? URL.createObjectURL(selected) : null);
    setResult(null);
  };

  const handleUpload = async () => {
    if (!file) return setError("Please select an image first.");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);
    setError(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });
      if (!response.ok) throw new Error("Server error!");
      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || "Something went wrong with the server!");
    }

    setLoading(false);
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <header style={styles.header}>
          <h1 style={styles.logo}>ClaimPilot AI</h1>
          <p style={styles.tagline}>Smart Vehicle Damage Assessment</p>
          <p style={styles.subtagline}>
            Upload an image of the damaged vehicle, and get instant repair cost
            estimates and fraud analysis.
          </p>
        </header>

        <div style={styles.uploadCard}>
          {preview && <img src={preview} alt="preview" style={styles.previewImage} />}
          <label style={styles.uploadLabel}>
            {file ? file.name : "Click or drag to upload image"}
            <input
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              onChange={handleFileChange}
            />
          </label>
          <div style={{ display: "flex", justifyContent: "center", gap: "10px" }}>
            <button
              onClick={handleUpload}
              disabled={loading}
              style={loading ? styles.buttonDisabled : styles.button}
            >
              {loading ? "Analyzing..." : "Run AI Audit"}
            </button>
            {file && (
              <button onClick={handleReset} style={styles.resetButton}>
                Reset
              </button>
            )}
          </div>
          {error && <p style={styles.error}>{error}</p>}
        </div>

        {result && (
          <div style={styles.resultCard}>
            <h2 style={styles.resultTitle}>Audit Summary</h2>

            <p style={styles.auditTime}>Audit Date: {new Date().toLocaleString()}</p>

            <div style={styles.stats}>
              <div style={styles.statBox}>
                <p>Total Estimate</p>
                <h3>PKR {result.total_estimate_pkr}</h3>
              </div>
              <div style={styles.statBox}>
                <p>Fraud Score</p>
                <h3>{result.fraud_confidence_score}</h3>
              </div>
              <div style={styles.statBox}>
                <p>Verdict</p>
                <h3>{result.verdict}</h3>
              </div>
              <div style={styles.statBox}>
                <p>Parts Count</p>
                <h3>{result.damaged_parts?.length || 0}</h3>
              </div>
            </div>

            <div style={styles.details}>
              <h3>Fraud Analysis</h3>
              <p>{result.fraud_analysis || "No fraud detected."}</p>

              <h3>Damaged Parts</h3>
              {result.damaged_parts?.length ? (
                <ul>
                  {result.damaged_parts.map((part, index) => (
                    <li key={index}>{part}</li>
                  ))}
                </ul>
              ) : (
                <p>No parts detected.</p>
              )}

              <h3>Itemized Costs</h3>
              <pre style={styles.pre}>
                {JSON.stringify(result.itemized_costs, null, 2)}
              </pre>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "#f4f7fa",
    display: "flex",
    justifyContent: "center",
    alignItems: "flex-start",
    padding: "40px 20px",
    fontFamily: "'Segoe UI', sans-serif",
  },
  container: {
    width: "100%",
    maxWidth: "900px",
    textAlign: "center",
    color: "#1e1e2f",
  },
  header: {
    marginBottom: "40px",
  },
  logo: {
    fontSize: "36px",
    fontWeight: "700",
    marginBottom: "5px",
  },
  tagline: {
    color: "#555",
    fontSize: "16px",
  },
  subtagline: {
    color: "#777",
    fontSize: "14px",
    marginTop: "8px",
  },
  uploadCard: {
    background: "#ffffff",
    padding: "30px",
    borderRadius: "16px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.05)",
    marginBottom: "40px",
    transition: "transform 0.3s",
  },
  uploadLabel: {
    display: "block",
    padding: "20px",
    border: "2px dashed #ccc",
    borderRadius: "12px",
    cursor: "pointer",
    marginBottom: "20px",
    transition: "all 0.3s",
  },
  previewImage: {
    width: "100%",
    maxHeight: "300px",
    objectFit: "cover",
    borderRadius: "12px",
    marginBottom: "15px",
  },
  button: {
    padding: "14px 30px",
    borderRadius: "10px",
    border: "none",
    background: "#1e40af",
    color: "#fff",
    fontWeight: "600",
    cursor: "pointer",
    transition: "0.3s",
  },
  buttonDisabled: {
    padding: "14px 30px",
    borderRadius: "10px",
    border: "none",
    background: "#aaa",
    color: "#fff",
    cursor: "not-allowed",
  },
  resetButton: {
    padding: "14px 30px",
    borderRadius: "10px",
    border: "none",
    background: "#ef4444",
    color: "#fff",
    fontWeight: "600",
    cursor: "pointer",
    transition: "0.3s",
  },
  error: {
    color: "#ef4444",
    marginTop: "10px",
  },
  resultCard: {
    background: "#fff",
    padding: "30px",
    borderRadius: "16px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.05)",
  },
  resultTitle: {
    marginBottom: "20px",
  },
  auditTime: {
    fontSize: "12px",
    color: "#777",
    marginBottom: "20px",
  },
  stats: {
    display: "flex",
    justifyContent: "space-between",
    gap: "20px",
    marginBottom: "30px",
    flexWrap: "wrap",
  },
  statBox: {
    flex: "1 1 150px",
    background: "#f4f7fa",
    padding: "20px",
    borderRadius: "12px",
  },
  details: {
    textAlign: "left",
    lineHeight: "1.6",
  },
  pre: {
    background: "#eee",
    padding: "15px",
    borderRadius: "8px",
    overflowX: "auto",
  },
};

export default App;
